(e=>{e(document).ready(function(){wu_event_payload_placeholders=new Vue({el:"#wu_event_payload_placeholders",data(){return{placeholders:[],event:e("select[name='event']").val(),search:"",loading:!0}},computed:{filtered_placeholders(){let a=this.search.toLowerCase();return _.filter(this.placeholders,function(e){return-1<e.name.toLowerCase().indexOf(a)||-1<e.placeholder.toLowerCase().indexOf(a)})}},watch:{event(){this.get_event_payload()}},methods:{get_event_payload(){let a=this;a.loading=!0,e.ajax({method:"post",url:ajaxurl,data:{action:"wu_get_event_payload_placeholders",email_event:a.event},success(e){a.placeholders=e,a.loading=!1},error(e){a.loading=!1,wu_ajax_error(e)}})}},mounted(){this.get_event_payload()}}),e(document).on("change",'select[name="event"]',function(){wu_event_payload_placeholders.event=e("select[name='event']").val()})})})(jQuery);